SourceCode.Declaration:
/// <summary>
/// Customer import
/// </summary>
public class ETG_Acu_CustomerImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_CustomerImport  customerImport;

    customerImport = ETG_Acu_CustomerImport::construct();

    if (customerImport.prompt())
    {
        customerImport.runOperation();
    }
}

public static ETG_Acu_CustomerImport construct()
{
    return new ETG_Acu_CustomerImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    CustCustomerV3Entity    customer;
    CustAccount             custAccount;

    custAccount = conpeek(_con, 1);

    if (!custAccount)
    {
        NumberSeq   numberSeq;

        numberSeq = NumberSeq::newGetNum(CustParameters::numRefCustAccount());

        customer.CustomerAccount                = numberSeq.num();
    }
    else
    {
        customer.CustomerAccount                = custAccount;
    }
    customer.OrganizationNumber             = conpeek(_con, 2);
    customer.AddressCity                    = conpeek(_con, 3);
    customer.AddressCountryRegionId         = conpeek(_con, 4);
    customer.AddressCountryRegionISOCode    = conpeek(_con, 5);
    customer.AddressDescription             = conpeek(_con, 6);
    customer.AddressState                   = conpeek(_con, 7);
    customer.AddressStreet                  = conpeek(_con, 8);
    customer.AddressZipCode                 = conpeek(_con, 9);
    customer.CustomerGroupId                = conpeek(_con, 10);
    //customer.DefaultDimensionDisplayValue   = conpeek(_con, 11);
    customer.DeliveryMode                   = conpeek(_con, 12);
    customer.DeliveryTerms                  = conpeek(_con, 13);
    customer.FullPrimaryAddress             = conpeek(_con, 14);

    if (conpeek(_con, 15))
    {
        customer.InvoiceAccount                 = conpeek(_con, 15);
    }
    else
    {
        customer.InvoiceAccount                 = customer.CustomerAccount; 
    }

    customer.InvoiceAddress                 = conpeek(_con, 16);
    customer.LanguageId                     = conpeek(_con, 17);
    customer.NameAlias                      = conpeek(_con, 18);
    customer.OnHoldStatus                   = conpeek(_con, 19);
    customer.OrganizationName               = conpeek(_con, 20);
    customer.PartyCountry                   = conpeek(_con, 21);
    customer.PartyType                      = conpeek(_con, 22);
    customer.PaymentTerms                   = conpeek(_con, 23);
    customer.PrimaryContactEmail            = conpeek(_con, 24);
    customer.PrimaryContactFax              = conpeek(_con, 25);
    customer.PrimaryContactPhone            = conpeek(_con, 26);
    customer.PrimaryContactURL              = conpeek(_con, 27);
    customer.SalesCurrencyCode              = conpeek(_con, 28);
    customer.SalesOrderPoolId               = conpeek(_con, 29);
    customer.SiteId                         = conpeek(_con, 30);
    customer.VendorAccount                  = conpeek(_con, 31);
    customer.WarehouseId                    = conpeek(_con, 32);

    // BusinessUnit (33)	Contract (34)	Department (35)	Intercompany (36)	Plant_Warehouse_Office (37)	Product_Service (38)	Trader_Employee (39)
    // |Plant_Warehouse_Office|Department|Trader_Employee|Product_Service|BusinessUnit|Intercompany|Contract

    customer.DefaultDimensionDisplayValue  = conPeek(_con, 37) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                            + conPeek(_con, 35) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                            + conPeek(_con, 39) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                            + conPeek(_con, 38) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                            + conPeek(_con, 33) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                            + conPeek(_con, 36) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                            + conPeek(_con, 34);
    customer.insert();
}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpCust";

    return ret;
}
